from flask import Flask, request, jsonify
from pymongo import MongoClient

app = Flask(__name__)
client = MongoClient('localhost', 27017)
db = client['contentmanagement']
User_Profile = db['userprofile']

@app.route("/storeprofile", methods=['POST'])
def storeprofile():
    data = request.get_json(force=True)
    User_Profile.insert_one(data)
    return "User Profile Stored Successfully"

@app.route("/queryprofiles", methods=['GET'])
def queryprofiles():
    query_parameter = request.args
    queried_data = list(User_Profile.find(query_parameter))
    for data in queried_data:
        data['_id'] = str(data['_id'])
    return jsonify(queried_data)

@app.route("/aggregate", methods=['POST'])
def aggregate():
    data = request.get_json(force=True)
    aggregated_data = list(User_Profile.aggregate(data))
    for data in aggregated_data:
        data['_id'] = str(data['_id'])
    return jsonify(aggregated_data)

if __name__ == "__main__":
    app.run(debug=True)